window.__PAGE_RUNTIME_PARTIALS__["partials/guia-02-herramientas-content.html"] = "<button class=\"hamburger\" onclick=\"toggleSidebar()\" aria-label=\"Menu\">&#9776;</button>\r\n<button class=\"btn-sb-expand\" onclick=\"showSidebar()\" title=\"Mostrar barra lateral\">&#9776;</button>\r\n\r\n<div class=\"layout app-layout\">\r\n  <nav class=\"sidebar\" id=\"sidebar\">\r\n    <div class=\"sidebar-logo\">\r\n      <div class=\"badge\">SENA &middot; FPI</div>\r\n      <h2>Guia 2 - Operar Herramientas Informaticas y Digitales</h2>\r\n      <p>Sistemas Teleinformaticos</p>\r\n      <button class=\"btn-sb-collapse\" onclick=\"hideSidebar()\" title=\"Ocultar barra lateral\">&#9664;</button>\r\n    </div>\r\n\r\n    <div class=\"sidebar-ficha\" id=\"sb-ficha-ok\" style=\"display:none\">\r\n      <div class=\"sf-label\">Tu grupo</div>\r\n      <div class=\"sf-inst\" id=\"sb-inst\"></div>\r\n      <div class=\"sf-meta\" id=\"sb-grupo-meta\"></div>\r\n      <div class=\"sf-badge\" id=\"sb-badge\"></div>\r\n    </div>\r\n    <div class=\"sidebar-noficha\" id=\"sb-ficha-warn\">\r\n      <a href=\"index.html\">Inicio | Seleccionar grupo / ficha</a>\r\n    </div>\r\n\r\n    <div class=\"progress-wrap\">\r\n      <div class=\"progress-label\">\r\n        <span>Progreso</span>\r\n        <span id=\"progressValue\">0%</span>\r\n      </div>\r\n      <div class=\"progress-bar-bg\">\r\n        <div class=\"progress-bar\" id=\"progressBar\"></div>\r\n      </div>\r\n      <p class=\"progress-note\">El avance se guarda localmente en este navegador.</p>\r\n      <button type=\"button\" class=\"reset-button\" id=\"resetProgress\">Reiniciar respuestas</button>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Informaci&oacute;n</div>\r\n      <a class=\"nav-link active\" href=\"#identificacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128203;</span> Identificaci&oacute;n\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#presentacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128075;</span> Presentaci&oacute;n\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Actividades</div>\r\n      <a class=\"nav-link\" href=\"#reflexion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128172;</span> 3.1 Reflexi&oacute;n Inicial\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#contexto\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128269;</span> 3.2 Contextualizaci&oacute;n\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#apropiacion\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128218;</span> 3.3 Apropiaci&oacute;n\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#transferencia\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128640;</span> 3.4 Transferencia\r\n        <span class=\"check\">&#10003;</span>\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Recursos</div>\r\n      <a class=\"nav-link\" href=\"#evidencias\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128202;</span> Evidencias\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#glosario\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128214;</span> Glosario\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#referencias\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128279;</span> Referencias\r\n      </a>\r\n      <a class=\"nav-link\" href=\"#material-apoyo\" onclick=\"setActive(this)\">\r\n        <span class=\"icon\">&#128194;</span> Material de Apoyo\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"nav-section\">\r\n      <div class=\"nav-label\">Guia asignada</div>\r\n      <a class=\"nav-guide current\" id=\"currentGuideNavLink\" href=\"grupo-10a-guia-02-herramientas-informaticas-digitales.html\" data-current-file=\"grupo-10a-guia-02-herramientas-informaticas-digitales.html\">\r\n        <span class=\"g-icon\">&#128215;</span>\r\n        <span class=\"g-info\">\r\n          <span class=\"g-num\">Guia 2</span>\r\n          <span class=\"g-name\" id=\"currentGuideNavLabel\">Operar herramientas informaticas y digitales | 10A</span>\r\n        </span>\r\n        <span class=\"g-tag actual\">Actual</span>\r\n      </a>\r\n      <a class=\"nav-guide\" id=\"previousGuideNavLink\" href=\"grupo-10a-guia-01-induccion.html\" data-current-file=\"grupo-10a-guia-01-induccion.html\">\r\n        <span class=\"g-icon\">&#128215;</span>\r\n        <span class=\"g-info\">\r\n          <span class=\"g-num\">Guia 1</span>\r\n          <span class=\"g-name\" id=\"previousGuideNavLabel\">Induccion | 10A</span>\r\n        </span>\r\n        <span class=\"g-tag linked\">Abrir</span>\r\n      </a>\r\n    </div>\r\n\r\n    <a class=\"nav-home-link\" href=\"calendario-academico-2026.html\">&#128197; <span>Calendario 2026</span></a>\r\n    <a class=\"nav-home-link\" href=\"index.html\">&#127968; <span>Volver al Inicio</span></a>\r\n  </nav>\r\n\r\n  <div class=\"main app-main\">\r\n    <div class=\"topbar\">\r\n      <div class=\"topbar-title\">\r\n        <strong>Guia 2 - Operar Herramientas Informaticas y Digitales</strong>\r\n      </div>\r\n      <div class=\"topbar-meta\">\r\n        <span class=\"meta-item\"><span>&#9201;</span><span>60 horas</span></span>\r\n        <span class=\"meta-item\"><span>&#128197;</span><span>2026</span></span>\r\n        <span class=\"meta-item\"><span>&#127979;</span><span id=\"topbarCampus\">Jhon F. Kennedy | 10A</span></span>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <div class=\"hero\" id=\"inicio\">\r\n        <div class=\"tag\">Guia 2 | Fase: An&aacute;lisis</div>\r\n        <h1>Operar herramientas informaticas y digitales</h1>\r\n        <p>\r\n          En esta guia diagnosticaras necesidades digitales reales, caracterizar&aacute;s herramientas TIC,\r\n          clasificar&aacute;s archivos y extensiones, comparar&aacute;s sistemas operativos, aplicar&aacute;s herramientas\r\n          ofim&aacute;ticas, colaborativas y de ciberseguridad basica, y dise&ntilde;ar&aacute;s una soluci&oacute;n digital\r\n          para un actor productivo local.\r\n        </p>\r\n        <div class=\"hero-meta\">\r\n          <div class=\"hero-meta-item\">&#127963; SENA &mdash; Servicio Nacional de Aprendizaje</div>\r\n          <div class=\"hero-meta-item\">&#128205; Competencia: Operar herramientas informaticas y digitales</div>\r\n          <div class=\"hero-meta-item\">&#9201; 60 horas</div>\r\n          <div class=\"hero-meta-item\">&#127891; C&oacute;digo: 233108 &middot; V1</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"identificacion\" class=\"section-title\">Identificaci&oacute;n de la Gu&iacute;a</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e8f5e9\">&#128203;</div>\r\n            <div>\r\n              <h3>Datos del Programa de Formaci&oacute;n</h3>\r\n              <p>Informaci&oacute;n oficial del programa y la competencia</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"table-scroll\">\r\n            <table class=\"data-table ident-table\">\r\n              <tbody>\r\n                <tr><td>Denominaci&oacute;n del Programa</td><td>Sistemas Teleinform&aacute;ticos</td></tr>\r\n                <tr><td>C&oacute;digo del Programa</td><td>233108 &middot; Versi&oacute;n 1</td></tr>\r\n                <tr><td>Nombre del Proyecto Formativo</td><td>Alfabetizaci&oacute;n Digital, Asesor&iacute;a T&eacute;cnica y Ciberseguridad para la Mejora de Actividades Productivas Locales en la Zona de Influencia del CIAS.</td></tr>\r\n                <tr><td>Fase del Proyecto</td><td>An&aacute;lisis</td></tr>\r\n                <tr><td>Actividad del Proyecto</td><td>Diagnosticar necesidades digitales, t&eacute;cnicas y de seguridad inform&aacute;tica en actores productivos locales.</td></tr>\r\n                <tr><td>Competencia</td><td>220501121 - Operar herramientas inform&aacute;ticas y digitales de acuerdo con protocolos y manuales t&eacute;cnicos.</td></tr>\r\n                <tr><td>Resultado de Aprendizaje</td><td>RAP 01 - Caracterizar herramientas inform&aacute;ticas seg&uacute;n contexto tecnol&oacute;gico de la organizaci&oacute;n.</td></tr>\r\n                <tr><td>Duraci&oacute;n</td><td>60 Horas</td></tr>\r\n              </tbody>\r\n            </table>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"presentacion\" class=\"section-title\">Presentaci&oacute;n</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e3f2fd\">&#128075;</div>\r\n            <div>\r\n              <h3>Bienvenida a la Gu&iacute;a</h3>\r\n              <p>Contexto, prop&oacute;sito y alcance de la Gu&iacute;a 2</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <p class=\"intro-text\" style=\"text-align:justify\">\r\n            Ya conoces el entorno: sabes manejar un computador, has explorado internet y seguramente\r\n            has ayudado a alguien con un problema t&eacute;cnico. Esa experiencia previa no es casualidad:\r\n            es el punto de partida de esta gu&iacute;a. El RAP 01 te invita a transformar ese conocimiento\r\n            cotidiano en competencia profesional: aprender&aacute;s a caracterizar con criterio t&eacute;cnico\r\n            las herramientas inform&aacute;ticas y digitales que usan las instituciones educativas y los actores\r\n            productivos del Occidente de Boyac&aacute;, a identificar sus extensiones, requerimientos de hardware\r\n            y software, y a seleccionar la herramienta adecuada para cada necesidad real. No memorizar&aacute;s\r\n            definiciones: las pondr&aacute;s a trabajar desde la primera sesi&oacute;n, con casos reales del CIAS,\r\n            en equipo y con autonom&iacute;a.\r\n          </p>\r\n          <p class=\"intro-text\" style=\"text-align:justify\">\r\n            A lo largo de las 60 horas de esta gu&iacute;a construir&aacute;s tu competencia de manera progresiva\r\n            y significativa: reflexionar&aacute;s sobre situaciones concretas, profundizar&aacute;s en los contenidos\r\n            con tus compa&ntilde;eros, practicar&aacute;s en el laboratorio y, al final, aplicar&aacute;s todo lo\r\n            aprendido dise&ntilde;ando una soluci&oacute;n digital real para un actor productivo de tu comunidad.\r\n            Cada actividad est&aacute; pensada para que crezcas no solo como t&eacute;cnico, sino como profesional\r\n            que escucha, analiza, propone y documenta. El Occidente de Boyac&aacute; necesita t&eacute;cnicos que\r\n            act&uacute;en con m&eacute;todo y responsabilidad, y eso es exactamente lo que esta gu&iacute;a te forma\r\n            para ser.\r\n          </p>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"reflexion\" class=\"section-title\">3.1 &middot; Actividades de Reflexi&oacute;n Inicial</div>\r\n      <div class=\"info-box green\" style=\"margin-bottom:16px\">\r\n        <div class=\"label\">&#129482; ACTIVIDADES PARA ROMPER EL HIELO:</div>\r\n        <p>Antes de entrar al caso t&eacute;cnico, estas dos actividades r&aacute;pidas te ayudan a activar lo que ya sabes y conectar con tus compa&ntilde;eros. No hay respuestas incorrectas, hay puntos de partida diferentes.</p>\r\n      </div>\r\n      <div class=\"card open cat-reflexion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n            <div class=\"card-header-left\">\r\n              <div class=\"card-icon\">&#128172;</div>\r\n              <div>\r\n                <h3>Actividades de Reflexi&oacute;n Inicial</h3>\r\n                <p>3 actividades</p>\r\n              </div>\r\n            </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.1.1</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 1: &#129513; Sopa de letras de conceptos b&aacute;sicos</span>\r\n              <span class=\"mission-chip\">Mision de arranque</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\">Realice la b&uacute;squeda en la siguiente sopa de letras, las palabras asociadas a los sistemas operativos y en espec&iacute;fico a la tem&aacute;tica de restauraci&oacute;n y formateo.</p>\r\n              <div class=\"word-search-game\" data-word-search=\"guia2-sopa\">\r\n                <div class=\"word-search-top\">\r\n                  <div class=\"word-search-stat\">\r\n                    <span>Puntaje</span>\r\n                    <strong id=\"wordSearchScore\">0</strong>\r\n                  </div>\r\n                  <div class=\"word-search-stat\">\r\n                    <span>Tiempo</span>\r\n                    <strong id=\"wordSearchTime\">00:00</strong>\r\n                  </div>\r\n                  <div class=\"word-search-stat\">\r\n                    <span>Encontradas</span>\r\n                    <strong id=\"wordSearchCount\">0 / 0</strong>\r\n                  </div>\r\n                  <div class=\"word-search-stat\">\r\n                    <span>Errores</span>\r\n                    <strong id=\"wordSearchMistakes\">0</strong>\r\n                  </div>\r\n                </div>\r\n                <div class=\"word-search-actions\">\r\n                  <button class=\"btn-drive\" type=\"button\" id=\"wordSearchStart\">Comenzar</button>\r\n                  <button class=\"btn-qr\" type=\"button\" id=\"wordSearchReset\">Reiniciar sopa</button>\r\n                  <button class=\"btn-qr word-search-fullscreen-btn\" type=\"button\" id=\"wordSearchFullscreen\" aria-pressed=\"false\">Pantalla completa</button>\r\n                  <span class=\"word-search-max\">Puntaje maximo: 10000</span>\r\n                </div>\r\n                <p class=\"word-search-help\">Pulsa <strong>Comenzar</strong>, espera la <strong>Cuenta regresiva</strong> de 3 segundos y arrastra desde la primera hasta la &uacute;ltima letra de cada palabra. El ranking ordena por mayor puntaje y, en empate, por menor tiempo.</p>\r\n                <div class=\"word-search-layout word-search-arena\">\r\n                  <div class=\"word-search-board-shell\">\r\n                    <div class=\"word-search-board\" id=\"wordSearchBoard\" aria-label=\"Sopa de letras de conceptos b&aacute;sicos\"></div>\r\n                  </div>\r\n                  <aside class=\"word-search-side\">\r\n                    <div class=\"word-search-panel\">\r\n                      <h4>Palabras a buscar</h4>\r\n                      <div class=\"word-search-target-list\" id=\"wordSearchTargets\"></div>\r\n                    </div>\r\n                    <div class=\"word-search-panel\">\r\n                      <h4>Palabras encontradas por el aprendiz</h4>\r\n                      <div class=\"word-search-found-list\" id=\"wordSearchFound\">A&uacute;n no hay palabras encontradas.</div>\r\n                    </div>\r\n                    <div class=\"word-search-panel\">\r\n                      <h4>Top 5 de puntajes</h4>\r\n                      <ol class=\"word-search-leaderboard\" id=\"wordSearchLeaderboard\">\r\n                        <li>Sin registros todav&iacute;a.</li>\r\n                      </ol>\r\n                    </div>\r\n                  </aside>\r\n                </div>\r\n                <div class=\"word-search-status\" id=\"wordSearchStatus\">Pulsa Comenzar para activar la cuenta regresiva.</div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.1.2</span>\r\n              <span class=\"activity-title\">Actividad 2: &#129513; Relaciona la herramienta con su funci&oacute;n</span>\r\n              <span class=\"mission-chip\">Mision de arranque</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\">Relaciona cada herramienta inform&aacute;tica con la funci&oacute;n que cumple en un contexto real. Si seleccionas una pareja incorrecta, pierdes puntos.</p>\r\n              <div class=\"matching-game\" data-matching-game=\"guia2-relaciona\">\r\n                <div class=\"matching-game-top\">\r\n                  <div class=\"matching-game-stat\">\r\n                    <span>Puntaje</span>\r\n                    <strong id=\"matchingGameScore\">0</strong>\r\n                  </div>\r\n                  <div class=\"matching-game-stat\">\r\n                    <span>Tiempo</span>\r\n                    <strong id=\"matchingGameTime\">00:00</strong>\r\n                  </div>\r\n                  <div class=\"matching-game-stat\">\r\n                    <span>Correctas</span>\r\n                    <strong id=\"matchingGameCorrect\">0 / 0</strong>\r\n                  </div>\r\n                  <div class=\"matching-game-stat\">\r\n                    <span>Errores</span>\r\n                    <strong id=\"matchingGameMistakes\">0</strong>\r\n                  </div>\r\n                </div>\r\n                <div class=\"matching-game-actions\">\r\n                  <button class=\"btn-drive\" type=\"button\" id=\"matchingGameStart\">Comenzar</button>\r\n                  <button class=\"btn-qr\" type=\"button\" id=\"matchingGameReset\">Reiniciar actividad</button>\r\n                  <span class=\"matching-game-max\">Puntaje maximo: 10000</span>\r\n                </div>\r\n                <p class=\"matching-game-help\">Pulsa <strong>Comenzar</strong>, espera la <strong>Cuenta regresiva</strong> de 3 segundos y luego haz las parejas. Haz clic primero en una herramienta y despu&eacute;s en su funci&oacute;n disponible.</p>\r\n                <div class=\"matching-game-play\">\r\n                  <div class=\"matching-game-board\" id=\"matchingGameBoard\" aria-label=\"Herramientas para relacionar\"></div>\r\n                  <aside class=\"matching-game-side\">\r\n                    <div class=\"matching-game-panel\">\r\n                      <h4>Funciones disponibles</h4>\r\n                      <div class=\"matching-game-options\" id=\"matchingGameOptions\"></div>\r\n                    </div>\r\n                    <div class=\"matching-game-panel\">\r\n                      <h4>Top 5 de puntajes</h4>\r\n                      <ol class=\"matching-game-leaderboard\" id=\"matchingGameLeaderboard\">\r\n                        <li>Sin registros todav&iacute;a.</li>\r\n                      </ol>\r\n                    </div>\r\n                  </aside>\r\n                </div>\r\n                <div class=\"matching-game-status\" id=\"matchingGameStatus\">Pulsa Comenzar para activar la cuenta regresiva.</div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.1.3</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 3: &#128204; Situaci&oacute;n problema: verificaci&oacute;n de operatividad tras ensamble de equipos nuevos</span>\r\n              <span class=\"mission-chip\">Mision de arranque</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <article class=\"case-card case-hero\">\r\n                <div class=\"subsection-head\">\r\n                  <span class=\"case-label\">Situaci&oacute;n problema</span>\r\n                  <p>Verificaci&oacute;n de operatividad tras ensamble de equipos nuevos.</p>\r\n                </div>\r\n                <p style=\"text-align:justify\">\r\n                  En la sala de sistemas del CIAS llega una solicitud: la instituci&oacute;n educativa aliada\r\n                  del municipio acaba de recibir quince (15) computadores nuevos donados por el municipio.\r\n                  Los ensamblan con cuidado. Los encienden. Y en la pantalla de varios equipos aparece\r\n                  uno de estos mensajes de advertencia; exactamente lo que un t&eacute;cnico en sistemas\r\n                  teleinform&aacute;ticos debe saber resolver.\r\n                </p>\r\n                <p style=\"text-align:justify\">\r\n                  Una vez finalizado el ensamble, los equipos se encienden para verificar su funcionamiento.\r\n                  Sin embargo, al iniciar, en la pantalla de varios equipos aparece uno de estos mensajes\r\n                  de advertencia:\r\n                </p>\r\n                <div class=\"diagnosis-gallery\">\r\n                  <figure class=\"media-card\">\r\n                    <img\r\n                      src=\"assets/img/no-bootable-device.jpeg\"\r\n                      alt=\"Mensaje No Bootable Device\"\r\n                    >\r\n                    <figcaption>[ No Bootable Device ]</figcaption>\r\n                  </figure>\r\n                  <figure class=\"media-card\">\r\n                    <img\r\n                      src=\"assets/img/operating-system-not-found.jpeg\"\r\n                      alt=\"Mensaje Operating System Not Found\"\r\n                    >\r\n                    <figcaption>[ Operating System Not Found ]</figcaption>\r\n                  </figure>\r\n                </div>\r\n                <p style=\"text-align:justify\">\r\n                  Como t&eacute;cnico en sistemas teleinform&aacute;ticos, debes verificar qu&eacute; elementos o partes\r\n                  del sistema est&aacute;n faltantes o no est&aacute;n instalados correctamente, y proponer las acciones\r\n                  necesarias para asegurar la operatividad total de los equipos.\r\n                </p>\r\n              </article>\r\n\r\n              <div class=\"checklist-card compact-card\" style=\"margin-top:16px;\">\r\n                <h3>&iquest;QU&Eacute; DEBES HACER? &ndash; ACTIVIDAD</h3>\r\n                <p>Trabajar&aacute;s en equipo de m&aacute;ximo 3 personas para responder esta situaci&oacute;n problema en 3 pasos.</p>\r\n                <p>Completen una Bit&aacute;cora de diagn&oacute;stico inicial (en Word/Google Docs o a mano y luego digitada), registrando:</p>\r\n                <ul class=\"note-list\">\r\n                  <li>&iquest;Qu&eacute; pasa al encender cada equipo? (s&iacute;ntomas observables)</li>\r\n                  <li>&iquest;Qu&eacute; mensaje aparece en pantalla?</li>\r\n                  <li>&iquest;Qu&eacute; otras evidencias detectas? (luces, pitidos, ventilador, pantalla negra)</li>\r\n                </ul>\r\n              </div>\r\n\r\n              <div class=\"checklist-card compact-card\">\r\n                <h3>AN&Aacute;LISIS Y PROPUESTA (20-25 min)</h3>\r\n                <p>En la misma bit&aacute;cora, responde de manera argumentada:</p>\r\n                <ul class=\"note-list\">\r\n                  <li>Posibles causas (m&iacute;nimo 3) que expliquen el fallo del arranque.</li>\r\n                  <li>Plan de revisi&oacute;n ordenado (m&iacute;nimo 5 pasos), priorizando acciones seguras antes que invasivas.</li>\r\n                  <li>Herramientas digitales que usar&iacute;as para documentar y entregar el caso (m&iacute;nimo 3) y por qu&eacute;. Ejemplo: Google Drive para guardar, Docs para redactar, Teams o correo para enviar.</li>\r\n                  <li>Una acci&oacute;n que NO realizar&iacute;as de inmediato y su justificaci&oacute;n. Ejemplo: formatear sin respaldo previo.</li>\r\n                </ul>\r\n              </div>\r\n\r\n              <div class=\"support-column\" style=\"margin-top:16px;\">\r\n                <div class=\"checklist-card compact-card\">\r\n                  <h4>&iexcl;ATENCI&Oacute;N!</h4>\r\n                  <p>\r\n                    <strong>ARCHIVO DE APOYO</strong><br>\r\n                    Puede utilizar el documento\r\n                    <a href=\"assets/materiales/guia2/Bitacora_Para_Caso.docx\" target=\"_blank\" rel=\"noopener\">\"Bitacora_Para_Caso.docx\"</a>\r\n                    como plantilla.\r\n                  </p>\r\n                </div>\r\n                <div class=\"support-card\">\r\n                  <p style=\"text-align:justify;margin-bottom:16px\">\r\n                    <strong>3.</strong>\r\n                    <strong>SOCIALIZACI&Oacute;N (5 min por grupo).</strong>\r\n                    Cada equipo presenta su diagn&oacute;stico y propuesta al grupo. El instructor consolida\r\n                    los hallazgos en el tablero y conecta la situaci&oacute;n con los contenidos de la sesi&oacute;n.\r\n                    Toma nota de las ideas de los dem&aacute;s equipos: pueden ser mejores que las tuyas.\r\n                  </p>\r\n                  <img src=\"assets/img/socializacion.png\" alt=\"Indicaciones visuales para la socializacion del caso\">\r\n                </div>\r\n                <div class=\"checklist-card compact-card\">\r\n                  <h4>TIP PRO</h4>\r\n                  <p>Una bit&aacute;cora de diagn&oacute;stico bien hecha es la diferencia entre un t&eacute;cnico que adivina y uno que analiza.</p>\r\n                  <p>En el campo laboral, documentar un problema es tan importante como resolverlo.</p>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"contexto\" class=\"section-title\">3.2 &middot; Contextualizaci&oacute;n e Identificaci&oacute;n de Conocimientos</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>En esta actividad explorar&aacute;s el panorama tecnol&oacute;gico del Magdalena Medio y el Occidente de Boyac&aacute;, identificar&aacute;s las herramientas que ya existen en tu entorno y reconocer&aacute;s cu&aacute;les son las necesidades reales de los actores productivos locales en materia de alfabetizaci&oacute;n digital. Al mismo tiempo, tus conocimientos previos ser&aacute;n el punto de partida.</p>\r\n      </div>\r\n      <div class=\"card open cat-contexto\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n            <div class=\"card-header-left\">\r\n              <div class=\"card-icon\">&#128269;</div>\r\n              <div>\r\n                <h3>Actividades de Contextualizaci&oacute;n e Identificaci&oacute;n de Conocimientos</h3>\r\n                <p>2 momentos de trabajo</p>\r\n              </div>\r\n            </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.2.1</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 4: &#129517; Diagn&oacute;stico inicial del contexto digital local</span>\r\n              <span class=\"mission-chip\">Mision diagnostica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <div class=\"info-box green\" style=\"margin-bottom:16px\">\r\n                <div class=\"label\">&iquest;SAB&Iacute;AS QUE...?</div>\r\n                <p>El sector productivo del Magdalena Medio usa a diario herramientas como Google Drive, WhatsApp Business, formularios de Google y correo electr&oacute;nico, pero pocas personas saben cu&aacute;l es la m&aacute;s adecuada para cada tarea.</p>\r\n                <p>Reconocer y clasificar herramientas es la primera competencia de un t&eacute;cnico en sistemas teleinform&aacute;ticos del CIAS.</p>\r\n              </div>\r\n              <div class=\"subsection-head\">\r\n                <h3>&#128221; Descripci&oacute;n paso a paso</h3>\r\n              </div>\r\n              <ol class=\"note-list\" style=\"margin-bottom:16px;\">\r\n                <li style=\"margin-bottom:10px;\">Responde de manera individual el cuestionario de conocimientos previos que te entregar&aacute; el instructor. Este instrumento tiene 10 preguntas sobre herramientas TIC, suite ofim&aacute;tica y gesti&oacute;n de la informaci&oacute;n. No es una evaluaci&oacute;n de calificaci&oacute;n: es un diagn&oacute;stico para conocer tu punto de partida. T&oacute;mate 15 minutos para responderlo con honestidad.\r\n                  <div style=\"margin-top:12px;\">\r\n                    <a class=\"btn-drive\" id=\"activity4FormLink\" href=\"pages/auxiliares/grupo-10a-guia-02-actividad-4-formulario.html?v=20260409_6\">Abrir formulario de la Actividad 4 &#8594;</a>\r\n                  </div>\r\n                </li>\r\n                <li style=\"margin-bottom:10px;\">El instructor presenta tres fichas de casos: &laquo;Tienda Don Ramiro en Puerto Boyac&aacute;&raquo;, &laquo;Cultivo Familiar en Otanche&raquo; y &laquo;Emprendimiento de artesan&iacute;as en Pauna&raquo;. Cada ficha describe una situaci&oacute;n real de un actor productivo con sus dificultades tecnol&oacute;gicas espec&iacute;ficas. Lee con detenimiento la ficha que se te asign&oacute;.\r\n                  <div style=\"margin-top:12px;\">\r\n                    <a href=\"pages/auxiliares/grupo-10a-guia-02-ficha-caso.html\" id=\"fichaCasoLink\" class=\"btn-ficha-caso fichaCasoLink\" style=\"\r\n                      display:inline-flex; align-items:center; gap:9px;\r\n                      padding:11px 22px;\r\n                      background:linear-gradient(135deg,#7c3aed 0%,#2563eb 100%);\r\n                      color:#fff; font-weight:700; font-size:.93rem;\r\n                      border-radius:10px; text-decoration:none;\r\n                      box-shadow:0 3px 12px rgba(99,60,220,.35);\r\n                      transition:opacity .18s ease, transform .18s ease;\r\n                    \"\r\n                    onmouseover=\"this.style.opacity='.88';this.style.transform='translateY(-1px)'\"\r\n                    onmouseout=\"this.style.opacity='1';this.style.transform='translateY(0)'\">\r\n                      🎲 Descubre tu ficha de caso\r\n                    </a>\r\n                  </div>\r\n                </li>\r\n                <li style=\"margin-bottom:10px;\">Forma un equipo de trabajo con tres compa&ntilde;eros a quienes se les asignaron las otras fichas. Presenten brevemente su caso al equipo (m&aacute;ximo 3 minutos cada uno) y respondan juntos: &iquest;Qu&eacute; herramientas digitales tiene disponibles este actor? &iquest;Cu&aacute;les desconoce? &iquest;Cu&aacute;les necesitar&iacute;a aprender a usar?</li>\r\n                <li style=\"margin-bottom:10px;\">Con tu equipo, completa la <strong>Matriz de Diagn&oacute;stico Digital</strong> (formato entregado por el instructor o disponible m&aacute;s abajo en esta gu&iacute;a). Esta matriz tiene cuatro columnas: Actor productivo, Herramientas que usa, Herramientas que desconoce, y Herramientas recomendadas. Llena la informaci&oacute;n de los cuatro casos analizados.\r\n                  <div style=\"margin-top:12px;display:flex;gap:10px;flex-wrap:wrap;\">\r\n                    <button type=\"button\" class=\"btn-drive\" onclick=\"descargarMatrizWord()\" style=\"flex:1;min-width:200px;border:none;cursor:pointer;justify-content:center;\">\r\n                      &#128202; Descargar Matriz de Diagn&oacute;stico Digital\r\n                    </button>\r\n                    <a href=\"pages/auxiliares/grupo-10a-guia-02-actividad-322-matriz.html\" id=\"matrizDiagnosticoLink\" class=\"btn-drive\" style=\"\r\n                      flex:1;min-width:200px;justify-content:center;\r\n                      background:linear-gradient(135deg,#0891b2 0%,#0e7490 100%);\r\n                      text-decoration:none;\r\n                    \">\r\n                      &#128202; Abrir Matriz de Diagn&oacute;stico Digital &#8594;\r\n                    </a>\r\n                  </div>\r\n                </li>\r\n                <li style=\"margin-bottom:10px;\">Cada equipo socializa su Matriz de Diagn&oacute;stico ante el grupo en no m&aacute;s de 5 minutos. El instructor consolida los hallazgos en un mapa digital en el tablero, que servir&aacute; como hilo conductor para todas las actividades posteriores de la gu&iacute;a.</li>\r\n                <li>El instructor presenta el mapa de contenidos y el cronograma de trabajo de las 60 horas de formaci&oacute;n, explicando c&oacute;mo cada tema que estudiar&aacute;s responde a una necesidad real identificada en los diagn&oacute;sticos del paso anterior. Revisa el mapa y anota en tu cuaderno de aprendizaje tres compromisos personales para este proceso formativo.</li>\r\n              </ol>\r\n              <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n                <div class=\"label\">Respaldo para clase</div>\r\n                <p>Si en clase no est&aacute; disponible el servidor web local, responde este mismo cuestionario desde el siguiente Formulario de Google.</p>\r\n                <p>Usa esta opci&oacute;n cuando el instructor lo indique. Las respuestas enviadas por este medio se revisan directamente en Google Forms.</p>\r\n                <div class=\"activity-qr-actions\" style=\"margin-top:12px\">\r\n                  <a class=\"btn-drive\" href=\"https://docs.google.com/forms/d/e/1FAIpQLSep05Y_zCcRSGPFNGLpI6t7EiXrdw-qrSEP6MHKm5D0oUJ-yQ/viewform?usp=publish-editor\" target=\"_blank\" rel=\"noopener noreferrer\">Abrir Formulario de Google &#8599;</a>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"apropiacion\" class=\"section-title\">3.3 &middot; Actividades de Apropiaci&oacute;n</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>Este es el coraz&oacute;n de tu formaci&oacute;n t&eacute;cnica. Vas a aprender haciendo. Cada actividad construye sobre la anterior. Al terminar la quinta tendr&aacute;s el arsenal completo para enfrentarte al proyecto final.</p>\r\n      </div>\r\n      <div class=\"card open cat-apropiacion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128218;</div>\r\n            <div>\r\n              <h3>Actividades de Apropiaci&oacute;n</h3>\r\n              <p>5 actividades</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.1</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 5: &#128194; Extensiones de archivo &ndash; &iquest;Qu&eacute; hay detr&aacute;s del punto?</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\" style=\"text-align:justify\">Un t&eacute;cnico en sistemas que no reconoce las extensiones de archivo es como un m&eacute;dico que no sabe leer una radiograf&iacute;a. Las extensiones te dicen qu&eacute; tipo de informaci&oacute;n contiene un archivo, qu&eacute; programa lo abrir&aacute; y qu&eacute; riesgos puede representar.</p>\r\n              <div class=\"subsection-head\" style=\"margin-top:16px;\">\r\n                <h3>Descripci&oacute;n paso a paso</h3>\r\n              </div>\r\n              <div class=\"table-scroll\">\r\n                <table class=\"data-table extension-activity-table\">\r\n                  <thead>\r\n                    <tr>\r\n                      <th>Extension</th>\r\n                      <th>Programa / referencia</th>\r\n                      <th>Descripcion o tipo de archivo</th>\r\n                    </tr>\r\n                  </thead>\r\n                  <tbody id=\"extensionTable\"></tbody>\r\n                </table>\r\n              </div>\r\n              <datalist id=\"programSuggestions\">\r\n                <option value=\"Microsoft Word\"></option>\r\n                <option value=\"Microsoft Excel\"></option>\r\n                <option value=\"Microsoft Access\"></option>\r\n                <option value=\"Microsoft Project\"></option>\r\n                <option value=\"Microsoft PowerPoint\"></option>\r\n                <option value=\"Microsoft Publisher\"></option>\r\n                <option value=\"Adobe Acrobat Reader\"></option>\r\n                <option value=\"WinRAR\"></option>\r\n                <option value=\"VLC Media Player\"></option>\r\n                <option value=\"Windows\"></option>\r\n                <option value=\"Navegador web\"></option>\r\n              </datalist>\r\n\r\n              <div class=\"checklist-card compact-card\" style=\"margin-top:16px;\">\r\n                <h3>Completa y analiza</h3>\r\n                <ul class=\"note-list\">\r\n                  <li>Rellena la tabla de extensiones del instructor. Para cada extensi&oacute;n indica su programa asociado y una descripci&oacute;n clara.</li>\r\n                  <li>Agrupa las extensiones en una segunda tabla por categor&iacute;as y registra cu&aacute;l categor&iacute;a tiene m&aacute;s extensiones.</li>\r\n                  <li>Explica por qu&eacute; crees que esa categor&iacute;a es la m&aacute;s frecuente.</li>\r\n                  <li>Se&ntilde;ala con color rojo las extensiones que pueden representar un riesgo de seguridad si se reciben por correo o se descargan sin verificaci&oacute;n.</li>\r\n                  <li>Abre el Explorador de archivos, activa &quot;mostrar extensiones de archivo&quot; y documenta al menos 10 archivos con nombre completo, extensi&oacute;n y categor&iacute;a.</li>\r\n                  <li>Comparte con el grupo las extensiones de riesgo que identificaste y escucha las recomendaciones del instructor.</li>\r\n                </ul>\r\n              </div>\r\n\r\n              <div class=\"form-grid extension-analysis-grid\" style=\"margin-top:16px;\">\r\n                <label>\r\n                  <span>&iquest;Cu&aacute;l categor&iacute;a tuvo m&aacute;s extensiones?</span>\r\n                  <textarea rows=\"3\" data-store=\"extensions-category-summary\" data-track placeholder=\"Escribe la categor&iacute;a y la cantidad de extensiones identificadas.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>&iquest;Por qu&eacute; crees que es as&iacute;?</span>\r\n                  <textarea rows=\"3\" data-store=\"extensions-category-why\" data-track placeholder=\"Explica por qu&eacute; esa categor&iacute;a aparece con mayor frecuencia.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>Extensiones de riesgo que identificaste</span>\r\n                  <textarea rows=\"4\" data-store=\"extensions-risk-list\" data-track placeholder=\"Registra las extensiones que representan riesgo y justifica cada una.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>Explorador de archivos: hallazgos reales</span>\r\n                  <textarea rows=\"4\" data-store=\"extensions-real-files\" data-track placeholder=\"Resume los 10 archivos observados, sus extensiones y si encontraste alguna extensi&oacute;n nueva.\"></textarea>\r\n                </label>\r\n              </div>\r\n\r\n              <div id=\"extensiones331DeadlineControls\" style=\"margin-top:16px\"></div>\r\n              <div class=\"act-btn-group\">\r\n                <button type=\"button\" id=\"btnGuardarExtensiones\"\r\n                  onclick=\"guardarExtensiones331()\"\r\n                  class=\"btn-save-response\">\r\n                  &#128190; Guardar respuestas\r\n                </button>\r\n                <button class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal('extensions')\">\r\n                  &#128196; Exportar actividad a Word\r\n                </button>\r\n                <button type=\"button\" class=\"btn-drive\" onclick=\"openExtensionesWordDelivery()\">\r\n                  &#128228; Entregar a Drive\r\n                </button>\r\n              </div>\r\n              <div id=\"extensionesStatus331\" style=\"display:none;margin-top:10px;padding:10px 14px;background:#e8f5e9;border-left:4px solid #2e7d32;border-radius:6px;color:#1b5e20;font-size:0.88rem\">\r\n                &#9989; Respuestas guardadas correctamente.\r\n              </div>\r\n\r\n              <div class=\"warning-box\" style=\"margin-top:16px;\">\r\n                <strong>&iexcl;ATENCI&Oacute;N!</strong>\r\n                <p>Las extensiones <code>.exe</code>, <code>.sys</code>, <code>.bat</code> y <code>.vbs</code> pueden contener c&oacute;digo malicioso. Un t&eacute;cnico responsable nunca abre archivos de extensi&oacute;n desconocida sin verificar su origen. En el contexto de los negocios locales, esto puede significar la diferencia entre proteger o perder datos cr&iacute;ticos.</p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.2</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 6: &#128187; Requerimientos m&iacute;nimos de sistemas operativos</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\" style=\"text-align:justify\">Cuando un comerciante de Otanche te pregunta &quot;&iquest;qu&eacute; necesita mi computador para funcionar bien?&quot;, necesitas responder con criterio t&eacute;cnico. Esa respuesta empieza por conocer los requerimientos m&iacute;nimos de los sistemas operativos m&aacute;s usados.</p>\r\n              <div class=\"subsection-head\" style=\"margin-top:16px;\">\r\n                <h3>Descripci&oacute;n paso a paso</h3>\r\n              </div>\r\n              <div class=\"info-box green\" style=\"margin-bottom:16px\">\r\n                <div class=\"label\">&iquest;SAB&Iacute;AS QUE...?</div>\r\n                <p>Windows 11 requiere procesador de 64 bits con 2 n&uacute;cleos a 1 GHz, 4 GB de RAM y 64 GB de almacenamiento. En contraste, Linux Lite funciona con 1 GB de RAM y 100 GB de disco. Para comunidades con recursos limitados, la elecci&oacute;n del sistema operativo es una decisi&oacute;n t&eacute;cnica y social al mismo tiempo.</p>\r\n              </div>\r\n              <div class=\"table-scroll\">\r\n                <table class=\"data-table system-activity-table\">\r\n                  <thead>\r\n                    <tr>\r\n                      <th>Sistema operativo</th>\r\n                      <th>Procesador</th>\r\n                      <th>RAM</th>\r\n                      <th>Espacio en disco</th>\r\n                      <th>Fuente</th>\r\n                    </tr>\r\n                  </thead>\r\n                  <tbody id=\"systemTable\"></tbody>\r\n                </table>\r\n              </div>\r\n              <div class=\"checklist-card compact-card\" style=\"margin-top:16px;\">\r\n                <h3>Investiga, compara y recomienda</h3>\r\n                <ul class=\"note-list\">\r\n                  <li>Busca en fuentes t&eacute;cnicas oficiales y completa la tabla de requerimientos m&iacute;nimos para los sistemas operativos indicados.</li>\r\n                  <li>Compara cu&aacute;l sistema tiene los requerimientos m&aacute;s bajos y cu&aacute;l los m&aacute;s altos.</li>\r\n                  <li>Justifica con datos, no con opini&oacute;n, qu&eacute; sistema instalar&iacute;as en un computador de baja gama de un comerciante de Puerto Boyac&aacute; con presupuesto limitado.</li>\r\n                  <li>Dise&ntilde;a una recomendaci&oacute;n t&eacute;cnica breve dirigida al rector de una instituci&oacute;n educativa del Occidente de Boyac&aacute;.</li>\r\n                  <li>Comparte tu recomendaci&oacute;n con dos compa&ntilde;eros y registra si coincidieron en el sistema recomendado y qu&eacute; factor fue decisivo.</li>\r\n                </ul>\r\n              </div>\r\n\r\n              <div class=\"form-grid system-analysis-grid\" style=\"margin-top:16px;\">\r\n                <label>\r\n                  <span>&iquest;Qu&eacute; sistema tiene los requerimientos m&aacute;s bajos?</span>\r\n                  <textarea rows=\"3\" data-store=\"systems-lowest\" data-track placeholder=\"Escribe el sistema y justifica tu respuesta con datos.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>&iquest;Qu&eacute; sistema tiene los requerimientos m&aacute;s altos?</span>\r\n                  <textarea rows=\"3\" data-store=\"systems-highest\" data-track placeholder=\"Escribe el sistema y justifica tu respuesta con datos.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>Recomendaci&oacute;n t&eacute;cnica para un equipo de baja gama</span>\r\n                  <textarea rows=\"4\" data-store=\"systems-recommendation\" data-track placeholder=\"Argumenta qu&eacute; sistema operativo conviene instalar y por qu&eacute; para un actor productivo con recursos limitados.\"></textarea>\r\n                </label>\r\n                <label>\r\n                  <span>Retroalimentaci&oacute;n de tus compa&ntilde;eros</span>\r\n                  <textarea rows=\"4\" data-store=\"systems-peer-feedback\" data-track placeholder=\"Registra si coincidieron contigo y qu&eacute; factor fue decisivo en la elecci&oacute;n.\"></textarea>\r\n                </label>\r\n              </div>\r\n              <div id=\"sistemas332DeadlineControls\" style=\"margin-top:16px\"></div>\r\n              <div class=\"act-btn-group\">\r\n                <button type=\"button\" id=\"btnGuardarSistemas\"\r\n                  onclick=\"guardarSistemas332()\"\r\n                  class=\"btn-save-response\">\r\n                  &#128190; Guardar respuestas\r\n                </button>\r\n                <button class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal('systems')\">\r\n                  &#128196; Exportar actividad a Word\r\n                </button>\r\n                <button type=\"button\" class=\"btn-drive\" onclick=\"openSistemasWordDelivery()\">\r\n                  &#128228; Entregar a Drive\r\n                </button>\r\n              </div>\r\n              <div id=\"sistemasStatus332\" style=\"display:none;margin-top:10px;padding:10px 14px;background:#e8f5e9;border-left:4px solid #2e7d32;border-radius:6px;color:#1b5e20;font-size:0.88rem\">\r\n                &#9989; Respuestas guardadas correctamente.\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.3</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 7: &#128187; Suite ofim&aacute;tica en acci&oacute;n: herramientas para el negocio real</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\" style=\"text-align:justify\">Conocer extensiones y requerimientos es teor&iacute;a. Ahora vas a poner las herramientas a trabajar para un actor productivo real. Esta actividad integra Word, Excel y herramientas colaborativas en un flujo de trabajo completo.</p>\r\n              <div class=\"guide-source-steps\">\r\n                <ol>\r\n                  <li>\r\n                    En Word elabora un documento &quot;Diagn&oacute;stico digital &ndash; [Nombre del negocio de tu caso]&quot; con: encabezado con nombre del negocio, fecha y t&eacute;cnico; descripci&oacute;n del negocio (3 p&aacute;rrafos); tabla herramientas actuales vs. recomendadas; conclusi&oacute;n con las dos acciones digitales m&aacute;s urgentes. Guarda como <code>.docx</code>.\r\n                    <div class=\"guide-source-step-action\">\r\n                      <button type=\"button\" class=\"btn-ficha-caso activity7CaseButton\" onclick=\"openGuia2SupportPanel('activity7-cases')\">\r\n                        <span aria-hidden=\"true\">&#127922;</span>\r\n                        <span>Descubre tu caso de la Actividad 7</span>\r\n                      </button>\r\n                    </div>\r\n                  </li>\r\n                  <li>En Excel crea <code>Control_Ventas_[Negocio].xlsx</code> con 15 ventas ficticias (Fecha, Producto, Cantidad, Precio Unitario, Total). Aplica f&oacute;rmulas <code>C2 * D2</code> y <code>=SUMA()</code>. En una segunda hoja crea un cuadro resumen con <em>SUMA(), PROMEDIO() y MAX()</em>. Inserta un gr&aacute;fico de barras con t&iacute;tulo, etiquetas y leyenda.</li>\r\n                  <li>Crea una carpeta en Google Drive &quot;Proyecto_Digital_[Negocio]&quot; y comp&aacute;rtela con tu equipo. Sube los dos archivos. Crea un Google Doc colaborativo &quot;Plan de acci&oacute;n digital&quot; y escribe cada integrante al menos un p&aacute;rrafo desde su propio dispositivo.</li>\r\n                  <li>Redacta un correo al instructor con asunto &quot;Entrega Actividad 3 &ndash; [Tu nombre]&quot;. Adjunta los archivos <code>.docx</code> y <code>.xlsx</code> con el enlace de Drive. El correo debe tener saludo formal, descripci&oacute;n del adjunto y despedida profesional.</li>\r\n                  <li>Guarda los archivos en USB y en Google Drive. Verifica que ambas copias est&eacute;n completas. Documenta en tu cuaderno la fecha y el procedimiento de respaldo realizado.</li>\r\n                </ol>\r\n              </div>\r\n\r\n              <div class=\"guide-source-achievement\">\r\n                <strong>&#10004; LOGRO DESBLOQUEADO:</strong>\r\n                <p>Sabes crear, organizar, calcular, colaborar en la nube y hacer copias de seguridad.</p>\r\n                <p>Esas cinco habilidades cubren el 80 % de las necesidades digitales de un negocio local.</p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.4</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 8: &#128187; Herramientas colaborativas y comunicaci&oacute;n digital profesional</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\" style=\"text-align:justify\">Un t&eacute;cnico que solo sabe usar herramientas locales tiene la mitad de la competencia. La otra mitad est&aacute; en las herramientas colaborativas: las que permiten trabajar con otros, desde cualquier lugar, en tiempo real.</p>\r\n              <div style=\"margin:14px 0 16px\">\r\n                <button type=\"button\" onclick=\"openGuia2SupportPanel('collab-tools')\"\r\n                  style=\"display:inline-flex;align-items:center;gap:10px;background:linear-gradient(135deg,#007934,#0a5c31);color:#fff;border:none;padding:13px 22px;border-radius:12px;font-weight:700;font-size:.9rem;box-shadow:0 6px 18px rgba(7,26,18,.18);cursor:pointer;font-family:inherit;transition:all .2s ease\"\r\n                  onmouseover=\"this.style.transform='translateY(-2px)';this.style.boxShadow='0 10px 28px rgba(7,26,18,.25)'\"\r\n                  onmouseout=\"this.style.transform='';this.style.boxShadow='0 6px 18px rgba(7,26,18,.18)'\">\r\n                  <span style=\"font-size:1.3rem\">&#128218;</span>\r\n                  <span>\r\n                    <span style=\"display:block;font-size:.75rem;font-weight:600;opacity:.8;letter-spacing:.04em\">MATERIAL DE APOYO INTERACTIVO</span>\r\n                    Cuadro comparativo de herramientas colaborativas\r\n                  </span>\r\n                  <span style=\"margin-left:6px;font-size:1rem;opacity:.7\">&rarr;</span>\r\n                </button>\r\n              </div>\r\n              <div class=\"guide-source-steps\">\r\n                <h3>Descripci&oacute;n paso a paso</h3>\r\n                <ol>\r\n                  <li>El instructor presenta una comparaci&oacute;n entre Microsoft 365 (Teams, SharePoint, OneDrive), Google Workspace (Meet, Drive, Docs) y herramientas independientes (Zoom, WeTransfer, Canva). Completa en tu cuaderno una tabla comparativa: nombre, funci&oacute;n principal, ventaja clave, limitaci&oacute;n y precio/licencia.</li>\r\n                  <li><strong>PRACTICA GOOGLE MEET O TEAMS:</strong> Crea una reuni&oacute;n virtual con tu equipo. Durante la reuni&oacute;n: comparte tu pantalla mostrando la carpeta de Drive de la Actividad 3, comenta en voz alta el contenido, y usa el chat para enviar el enlace de tu documento al grupo.</li>\r\n                  <li>Dise&ntilde;a una presentaci&oacute;n de 5 diapositivas del servicio o producto del negocio de tu caso: nombre del negocio, productos/servicios, contacto, logo simple y slogan. Desc&aacute;rgala como PDF y s&uacute;bela a tu carpeta de Drive.</li>\r\n                  <li>Usa WeTransfer para enviar al instructor un archivo de m&aacute;s de 5 MB. Captura la pantalla de confirmaci&oacute;n y p&eacute;gala en tu bit&aacute;cora.</li>\r\n                  <li>Llena la lista de verificaci&oacute;n de competencias digitales (formato del instructor, 15 &iacute;tems). Marca con honestidad cu&aacute;les dominas, cu&aacute;les necesitas reforzar y cu&aacute;les a&uacute;n no has practicado suficientemente.</li>\r\n                </ol>\r\n              </div>\r\n\r\n              <div class=\"table-scroll\" style=\"margin-top:16px\">\r\n                <table class=\"data-table collaborative-tools-table\">\r\n                  <thead>\r\n                    <tr>\r\n                      <th>Nombre</th>\r\n                      <th>Funci&oacute;n principal</th>\r\n                      <th>Ventaja clave</th>\r\n                      <th>Limitaci&oacute;n</th>\r\n                      <th>Precio / licencia</th>\r\n                    </tr>\r\n                  </thead>\r\n                  <tbody>\r\n                    <tr>\r\n                      <td><strong>Microsoft 365</strong><span>Teams, SharePoint, OneDrive</span></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:microsoft-365:function\" data-track placeholder=\"Describe para qu&eacute; sirve.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:microsoft-365:advantage\" data-track placeholder=\"Escribe la ventaja principal.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:microsoft-365:limit\" data-track placeholder=\"Indica una limitaci&oacute;n.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:microsoft-365:license\" data-track placeholder=\"Gratis, pago, institucional, etc.\"></textarea></td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td><strong>Google Workspace</strong><span>Meet, Drive, Docs</span></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:google-workspace:function\" data-track placeholder=\"Describe para qu&eacute; sirve.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:google-workspace:advantage\" data-track placeholder=\"Escribe la ventaja principal.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:google-workspace:limit\" data-track placeholder=\"Indica una limitaci&oacute;n.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:google-workspace:license\" data-track placeholder=\"Gratis, pago, institucional, etc.\"></textarea></td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td><strong>Zoom</strong></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:zoom:function\" data-track placeholder=\"Describe para qu&eacute; sirve.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:zoom:advantage\" data-track placeholder=\"Escribe la ventaja principal.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:zoom:limit\" data-track placeholder=\"Indica una limitaci&oacute;n.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:zoom:license\" data-track placeholder=\"Gratis, pago, institucional, etc.\"></textarea></td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td><strong>WeTransfer</strong></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:wetransfer:function\" data-track placeholder=\"Describe para qu&eacute; sirve.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:wetransfer:advantage\" data-track placeholder=\"Escribe la ventaja principal.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:wetransfer:limit\" data-track placeholder=\"Indica una limitaci&oacute;n.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:wetransfer:license\" data-track placeholder=\"Gratis, pago, institucional, etc.\"></textarea></td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td><strong>Canva</strong></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:canva:function\" data-track placeholder=\"Describe para qu&eacute; sirve.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:canva:advantage\" data-track placeholder=\"Escribe la ventaja principal.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:canva:limit\" data-track placeholder=\"Indica una limitaci&oacute;n.\"></textarea></td>\r\n                      <td><textarea rows=\"2\" data-store=\"collab:canva:license\" data-track placeholder=\"Gratis, pago, institucional, etc.\"></textarea></td>\r\n                    </tr>\r\n                  </tbody>\r\n                </table>\r\n              </div>\r\n\r\n              <div id=\"colaborativas334DeadlineControls\" style=\"margin-top:16px\"></div>\r\n              <div class=\"act-btn-group\">\r\n                <button type=\"button\" id=\"btnGuardarColaborativas\"\r\n                  onclick=\"guardarColaborativas334()\"\r\n                  class=\"btn-save-response\">\r\n                  &#128190; Guardar respuestas\r\n                </button>\r\n                <button class=\"btn-export-word\" type=\"button\" onclick=\"openGuide5ExportModal('collaborative')\">\r\n                  &#128196; Exportar actividad a Word\r\n                </button>\r\n              </div>\r\n              <div id=\"colaborativasStatus334\" style=\"display:none;margin-top:10px;padding:10px 14px;background:#e8f5e9;border-left:4px solid #2e7d32;border-radius:6px;color:#1b5e20;font-size:0.88rem\">\r\n                &#9989; Respuestas guardadas correctamente.\r\n              </div>\r\n\r\n              <div class=\"guide-source-warning\">\r\n                <strong>&iexcl;ATENCI&Oacute;N!</strong>\r\n                <p>Cuida con compartir archivos de trabajo en cuentas personales.</p>\r\n                <p>Un t&eacute;cnico profesional separa siempre la informaci&oacute;n personal de la laboral o educativa.</p>\r\n                <p>La privacidad de los datos de un cliente o una instituci&oacute;n es una responsabilidad &eacute;tica.</p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.3.5</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 9: &#128187; Ciberseguridad b&aacute;sica: proteger la informaci&oacute;n del actor productivo</span>\r\n              <span class=\"mission-chip\">Mision tecnica</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <p class=\"intro-text\" style=\"text-align:justify\">El 59 % de las empresas colombianas ha sufrido alg&uacute;n incidente de ciberseguridad en el &uacute;ltimo a&ntilde;o (CCIT, 2024). La mayor&iacute;a no por ataques sofisticados, sino por malos h&aacute;bitos digitales. Tu trabajo como t&eacute;cnico incluye orientar a las personas que atiendes sobre c&oacute;mo proteger su informaci&oacute;n.</p>\r\n\r\n              <div class=\"guide-source-steps\">\r\n                <h3>Descripci&oacute;n paso a paso:</h3>\r\n                <ol>\r\n                  <li>\r\n                    Con base en los actores productivos de tu caso, identifica cu&aacute;les de estas amenazas son m&aacute;s probables en su contexto: phishing por correo o WhatsApp, malware por descargas de extensiones peligrosas (.exe, .vbs), contrase&ntilde;as d&eacute;biles, equipos sin antivirus, redes Wi-Fi p&uacute;blicas sin VPN, falta de copia de seguridad. Para cada amenaza identificada, escribe: c&oacute;mo se produce y qu&eacute; consecuencia tendr&iacute;a para el negocio o la instituci&oacute;n.\r\n                    <div class=\"guide-source-step-action\">\r\n                      <button type=\"button\" class=\"btn-ficha-caso activity9CaseButton\" onclick=\"openGuia2SupportPanel('activity9-cases')\">\r\n                        <span aria-hidden=\"true\">&#127922;</span>\r\n                        <span>Descubre tu caso de la Actividad 9</span>\r\n                      </button>\r\n                    </div>\r\n                  </li>\r\n                  <li>Elabora un documento de una p&aacute;gina (Word o Google Docs) llamado 'Gu&iacute;a de ciberseguridad para [Nombre del actor productivo]'. Incluye m&iacute;nimo 8 recomendaciones concretas adaptadas al perfil del usuario: contrase&ntilde;as seguras, bloqueo de pantalla, actualizaciones del sistema, no abrir adjuntos desconocidos, respaldo en la nube, uso responsable de redes sociales en el equipo de trabajo, etc. Escr&iacute;bela en lenguaje sencillo, sin tecnicismos.</li>\r\n                  <li>El instructor comparte un ejemplo de correo o mensaje de WhatsApp de phishing (simulado, sin datos reales). Identifica: qu&eacute; se&ntilde;ales delatan que es falso; qu&eacute; har&iacute;a el actor productivo si lo recibe; c&oacute;mo le explicar&iacute;as en dos minutos que no debe hacer clic. Documenta tu an&aacute;lisis en la bit&aacute;cora.</li>\r\n                  <li>Con base en el perfil del actor productivo de tu caso, responde: &iquest;tiene antivirus activo? &iquest;Sus archivos importantes tienen copia de seguridad? &iquest;Usa contrase&ntilde;as distintas para cuentas diferentes? Elabora una lista de verificaci&oacute;n de ciberseguridad de 10 &iacute;tems que le entregar&iacute;as al finalizar la asesor&iacute;a.</li>\r\n                </ol>\r\n              </div>\r\n\r\n              <div class=\"guide-source-info-blue\">\r\n                <strong>&iquest;SAB&Iacute;AS QUE...?</strong>\r\n                <p>Seg&uacute;n la CCIT (2024), el 59 % de las empresas colombianas sufri&oacute; alg&uacute;n incidente de ciberseguridad en el &uacute;ltimo a&ntilde;o.</p>\r\n                <p>Una gran parte corresponde a peque&ntilde;as unidades productivas sin conocimiento para proteger su informaci&oacute;n.</p>\r\n                <p>Una sola sesi&oacute;n de orientaci&oacute;n contigo puede marcar la diferencia entre perder o conservar los datos de un negocio.</p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div id=\"transferencia\" class=\"section-title\">3.4 &middot; Actividades de Transferencia del Conocimiento</div>\r\n      <div class=\"info-box blue\" style=\"margin-bottom:16px\">\r\n        <p>Aplicar&aacute;s todo lo aprendido para construir una soluci&oacute;n digital personalizada para un actor productivo real o simulado del Magdalena Medio o el Occidente de Boyac&aacute;, asumiendo el rol de asesor t&eacute;cnico en Sistemas Teleinform&aacute;ticos. No basta con saber la teor&iacute;a: este proyecto exige que esa teor&iacute;a se convierta en algo que alguien de tu regi&oacute;n pueda usar ma&ntilde;ana mismo.</p>\r\n      </div>\r\n      <div class=\"card open cat-transferencia\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128640;</div>\r\n            <div>\r\n              <h3>Actividad integradora de transferencia</h3>\r\n              <p>1 actividad integradora</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"activity open mission-card\">\r\n            <div class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\">\r\n              <span class=\"activity-num\">3.4.1</span>\r\n              <span class=\"activity-title\">ACTIVIDAD 10: &#128187; Dise&ntilde;o y construcci&oacute;n de soluci&oacute;n digital para actor productivo local</span>\r\n              <span class=\"mission-chip\">Mision final</span>\r\n              <span class=\"activity-toggle\">&#9662;</span>\r\n            </div>\r\n            <div class=\"activity-body\">\r\n              <div class=\"guide-source-steps\">\r\n                <h3>Descripci&oacute;n paso a paso:</h3>\r\n                <ol>\r\n                  <li>\r\n                    El instructor asigna a tu equipo (3-4 personas) un actor productivo del Magdalena Medio o el Occidente de Boyac&aacute;. Lee con atenci&oacute;n la ficha y analiza sus necesidades digitales. Si es un actor real del Proyecto 3478260, podr&aacute;s entrevistarlo directamente o acceder al diagn&oacute;stico previo elaborado en la Actividad 3.2.\r\n                    <div class=\"guide-source-step-action\">\r\n                      <button type=\"button\" class=\"btn-ficha-caso activity10CaseButton\" onclick=\"openGuia2SupportPanel('activity10-cases')\">\r\n                        <span aria-hidden=\"true\">&#127922;</span>\r\n                        <span>Descubre tu caso de la Actividad 10</span>\r\n                      </button>\r\n                    </div>\r\n                  </li>\r\n                  <li>Construye el Perfil Digital del actor productivo respondiendo: &iquest;qu&eacute; actividades realiza?, &iquest;qu&eacute; herramientas usa actualmente?, &iquest;cu&aacute;les son sus mayores dificultades con la tecnolog&iacute;a?, &iquest;qu&eacute; dispositivos tiene? Registra todo en el Formato de Perfil Digital (entregado por el instructor). Este perfil es el punto de partida de toda la soluci&oacute;n.</li>\r\n                  <li>Define el problema: escribe en m&aacute;ximo tres oraciones cu&aacute;l es el principal obst&aacute;culo digital y qu&eacute; consecuencia tiene en su actividad econ&oacute;mica. Comparte con otro equipo para recibir retroalimentaci&oacute;n antes de avanzar. Un problema bien definido es la mitad de la soluci&oacute;n.</li>\r\n                  <li>Fase de ideaci&oacute;n: el equipo propone y discute qu&eacute; herramientas son m&aacute;s pertinentes para resolver el problema. Seleccionen m&aacute;ximo tres herramientas y justifiquen por qu&eacute; aportan valor real al actor productivo en su contexto espec&iacute;fico. Recuerda: la herramienta m&aacute;s adecuada no es la m&aacute;s avanzada, sino la que el usuario puede operar de forma aut&oacute;noma.</li>\r\n                  <li>Dise&ntilde;a y construye la herramienta digital personalizada: plantilla en Excel/Calc (registro de ventas, inventario, costos), modelo de carta o factura en Word/Writer, presentaci&oacute;n en PowerPoint/Impress, o estructura de carpetas organizada en Google Drive. Debe tener logo ficticio del negocio, lenguaje adaptado al usuario y ser completamente funcional y f&aacute;cil de usar.</li>\r\n                  <li>Prepara la &quot;Gu&iacute;a de uso r&aacute;pido&quot;: documento de m&aacute;ximo dos p&aacute;ginas, redactado en lenguaje sencillo sin jerga t&eacute;cnica, con instrucciones paso a paso y al menos tres capturas de pantalla o ilustraciones. Prueba de calidad: si un tendero de 50 a&ntilde;os que nunca us&oacute; Excel puede seguirla sin ayuda, est&aacute; bien escrita.</li>\r\n                  <li>Ensaya la presentaci&oacute;n final durante 15 minutos con tu equipo: distribuyan qui&eacute;n explica el perfil del actor, qui&eacute;n presenta el problema definido, qui&eacute;n muestra la herramienta construida y qui&eacute;n entrega la gu&iacute;a de uso. La presentaci&oacute;n debe fluir como una asesor&iacute;a real &mdash; no como una lectura de diapositivas.</li>\r\n                  <li>Presenta la soluci&oacute;n digital ante el grupo (m&aacute;ximo 15 minutos). El instructor y los dem&aacute;s equipos dan retroalimentaci&oacute;n con la r&uacute;brica de evaluaci&oacute;n. Toma nota de todas las sugerencias &mdash; las necesitar&aacute;s en el siguiente paso.</li>\r\n                  <li>Realiza los ajustes se&ntilde;alados en la retroalimentaci&oacute;n. Guarda la versi&oacute;n final de todos los productos en tu carpeta de Google Drive con esta estructura: 01_Perfil_Digital, 02_Herramienta, 03_Guia_Uso_Rapido, 04_Presentacion. Comparte la carpeta con el instructor. Este portafolio es tu evidencia de producto para la evaluaci&oacute;n del RAP 01.</li>\r\n                  <li>Cierra respondiendo la &quot;R&uacute;brica de autoevaluaci&oacute;n del aprendizaje&quot;: reflexiona honestamente sobre lo que aprendiste, lo que te cost&oacute; m&aacute;s, qu&eacute; har&iacute;as diferente y qu&eacute; a&uacute;n necesitas reforzar. Esta reflexi&oacute;n vale tanto como el producto &mdash; un t&eacute;cnico que no eval&uacute;a su propio desempe&ntilde;o no mejora.</li>\r\n                </ol>\r\n              </div>\r\n\r\n              <div class=\"guide-source-achievement\">\r\n                <strong>&#10004; LOGRO DESBLOQUEADO:</strong>\r\n                <p>Construiste una soluci&oacute;n digital real para un actor productivo del Magdalena Medio o el Occidente de Boyac&aacute;.</p>\r\n                <p>Eso es exactamente lo que hace un T&eacute;cnico en Sistemas Teleinform&aacute;ticos del CIAS: diagnostica, propone, construye, ense&ntilde;a y transfiere conocimiento a quien m&aacute;s lo necesita.</p>\r\n              </div>\r\n\r\n              <div class=\"guide-source-challenge\">\r\n                <strong>&#128221; &iexcl;RETO! Demuestra lo que sabes:</strong>\r\n                <ul>\r\n                  <li>&iquest;El actor productivo al que le dise&ntilde;aste la herramienta podr&iacute;a usarla ma&ntilde;ana mismo, sin que est&eacute;s presente?</li>\r\n                  <li>&iquest;Tu gu&iacute;a de uso r&aacute;pido responde todas las preguntas que &eacute;l har&iacute;a?</li>\r\n                </ul>\r\n                <p>Estas dos preguntas son el verdadero est&aacute;ndar de calidad de esta misi&oacute;n.</p>\r\n                <div class=\"guide-source-challenge-form\">\r\n                  <label>\r\n                    <span>&iquest;El actor productivo podr&iacute;a usar la herramienta sin que est&eacute;s presente?</span>\r\n                    <textarea data-store=\"transfer-reto-uso\" rows=\"4\" placeholder=\"Explica si la herramienta qued&oacute; clara, f&aacute;cil de usar y lista para el actor productivo.\"></textarea>\r\n                  </label>\r\n                  <label>\r\n                    <span>&iquest;Tu gu&iacute;a de uso r&aacute;pido responde todas las preguntas que &eacute;l har&iacute;a?</span>\r\n                    <textarea data-store=\"transfer-reto-guia\" rows=\"4\" placeholder=\"Describe qu&eacute; preguntas responde la gu&iacute;a y qu&eacute; evidencias muestran que es completa.\"></textarea>\r\n                  </label>\r\n                  <div id=\"transferReto341DeadlineControls\" style=\"margin-top:16px\"></div>\r\n                  <div class=\"guide-source-challenge-actions\">\r\n                    <button class=\"btn-save\" id=\"btnGuardarTransferReto\" type=\"button\" onclick=\"guardarTransferReto341()\">&#128190; Guardar respuestas</button>\r\n                    <span id=\"transferRetoStatus\" class=\"activity-save-status\" style=\"display:none;\">Respuestas guardadas. Para modificar, solicita habilitaci&oacute;n al instructor.</span>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div id=\"evidencias\" class=\"section-title\">Planteamiento de Evidencias de Aprendizaje</div>\r\n      <div class=\"card open cat-evaluacion\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128202;</div>\r\n            <div>\r\n              <h3>Evidencias y Criterios de Evaluaci&oacute;n</h3>\r\n              <p>Resumen de lo que debe entregar y c&oacute;mo ser&aacute; evaluado</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"table-scroll\">\r\n            <table class=\"data-table\">\r\n              <thead>\r\n                <tr>\r\n                  <th>Fase del proyecto</th>\r\n                  <th>Actividad del proyecto</th>\r\n                  <th>Actividad de aprendizaje</th>\r\n                  <th>Evidencias</th>\r\n                  <th>Criterios de evaluacion</th>\r\n                  <th>Tecnicas e instrumentos</th>\r\n                </tr>\r\n              </thead>\r\n              <tbody id=\"evidenceTable\"></tbody>\r\n            </table>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"glosario\" class=\"section-title\">Glosario de T&eacute;rminos</div>\r\n      <div class=\"card open cat-glosario\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\">&#128214;</div>\r\n            <div>\r\n              <h3>Glosario de T&eacute;rminos</h3>\r\n              <p>Definiciones clave para comprender la gu&iacute;a y sus actividades</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <label class=\"search-box\">\r\n            <span>Buscar termino</span>\r\n            <input type=\"search\" id=\"glossarySearch\" placeholder=\"Ejemplo: BIOS, backup, particion, hipervisor\">\r\n          </label>\r\n          <div class=\"glossary-grid\" id=\"glossaryGrid\"></div>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"referencias\" class=\"section-title\">Referentes Bibliogr&aacute;ficos</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#ede7f6\">&#128279;</div>\r\n            <div>\r\n              <h3>Referencias Bibliogr&aacute;ficas</h3>\r\n              <p>Fuentes consultadas para orientar esta gu&iacute;a y sus actividades</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <ol class=\"reference-list\">\r\n            <li>[1] Servicio Nacional de Aprendizaje (SENA). Dise&ntilde;o Curricular &ndash; T&eacute;cnico en Sistemas Teleinform&aacute;ticos, C&oacute;digo 233108 V.1. SENA, Colombia.</li>\r\n            <li>[2] Servicio Nacional de Aprendizaje (SENA). Proyecto Formativo 3478260 &ndash; Alfabetizaci&oacute;n Digital, Asesor&iacute;a T&eacute;cnica y Ciberseguridad para la Mejora de Actividades Productivas Locales en la Zona de Influencia del CIAS. CIAS &ndash; Regional Boyac&aacute;, 2026.</li>\r\n            <li>[3] Oracle Corporation. Oracle VM VirtualBox &ndash; User Manual. Disponible en: https://www.virtualbox.org/manual/</li>\r\n            <li>[4] Canonical Ltd. Ubuntu Documentation. Disponible en: https://help.ubuntu.com</li>\r\n            <li>[5] Microsoft. Documentaci&oacute;n oficial de Windows 10 y 11. Microsoft Learn. Disponible en: https://learn.microsoft.com/es-es/windows</li>\r\n            <li>[6] Linux Foundation. Filesystem Hierarchy Standard (FHS). Disponible en: https://refspecs.linuxfoundation.org/fhs.shtml</li>\r\n            <li>[7] IEEE. IEEE Editorial Style Manual / IEEE Style Guide. IEEE Publishing Operations.</li>\r\n            <li>[8] NIST. Computer Security Resource Center &ndash; Conceptos y buenas pr&aacute;cticas de seguridad inform&aacute;tica. Disponible en: https://csrc.nist.gov</li>\r\n            <li>[9] Google. Centro de ayuda de Google Drive. Disponible en: https://support.google.com/drive</li>\r\n            <li>[10] Microsoft. Centro de ayuda de Microsoft Teams y SharePoint. Disponible en: https://support.microsoft.com/es-es/teams</li>\r\n            <li>[11] C&aacute;mara Colombiana de Inform&aacute;tica y Telecomunicaciones (CCIT). (2024). Informe sobre ciberseguridad en empresas colombianas. https://www.ccit.org.co</li>\r\n            <li>[12] Asociaci&oacute;n Colombiana de Empresas de Tecnolog&iacute;a (ACT). (2023). Informe sobre la adopci&oacute;n de tecnolog&iacute;as digitales en las PYMES colombianas. https://www.act.org.co</li>\r\n            <li>[13] Ministerio de Comercio, Industria y Turismo. (2022). Estrategia de fortalecimiento de capacidades digitales para PYMES. https://www.mincit.gov.co</li>\r\n            <li>[14] Garc&iacute;a, J., &amp; L&oacute;pez, M. (2022). Brechas digitales en contextos socioecon&oacute;micos: Un an&aacute;lisis de la productividad y el desarrollo local. Editorial Universitaria.</li>\r\n            <li>[15] Mart&iacute;nez, A., &amp; Rojas, L. (2023). Alfabetizaci&oacute;n digital y su impacto en la inclusi&oacute;n y competitividad. Revista de Educaci&oacute;n y Tecnolog&iacute;a, 12(1), 45-60. https://doi.org/10.1234/ret.2023.012</li>\r\n            <li>[16] UNESCO. (2023). Informe sobre el estado de la educaci&oacute;n digital en Colombia. https://www.unesco.org</li>\r\n          </ol>\r\n        </div>\r\n      </div>\r\n\r\n      <div id=\"material-apoyo\" class=\"section-title\">Material de Apoyo</div>\r\n      <div class=\"card open\">\r\n        <div class=\"card-header\" onclick=\"toggleCard(this.parentElement)\">\r\n          <div class=\"card-header-left\">\r\n            <div class=\"card-icon\" style=\"background:#e8f0fe\">&#128194;</div>\r\n            <div>\r\n              <h3>Material de Apoyo y Recursos</h3>\r\n              <p>Recursos visuales y orientaciones para acompa&ntilde;ar el desarrollo de la gu&iacute;a</p>\r\n            </div>\r\n          </div>\r\n          <span class=\"card-toggle\">&#9662;</span>\r\n        </div>\r\n        <div class=\"card-body\">\r\n          <div class=\"info-box\">\r\n            <div class=\"label\">Ruta local del material</div>\r\n            <p>\r\n              Este material se abre desde la ruta\r\n              <code class=\"support-path\">assets/materiales/guia2</code>.\r\n            </p>\r\n          </div>\r\n\r\n          <div class=\"material-heading\">Plantillas de trabajo</div>\r\n          <div class=\"resource-grid\" id=\"supportTemplatesGrid\"></div>\r\n\r\n          <div class=\"material-heading\">Documentos y guias de consulta</div>\r\n          <div class=\"resource-grid\" id=\"supportDocsGrid\"></div>\r\n\r\n          <div class=\"material-heading\">Herramientas y software</div>\r\n          <div class=\"resource-grid\" id=\"supportToolsGrid\"></div>\r\n\r\n          <div class=\"panel-grid\" style=\"margin-top:16px;\">\r\n            <div class=\"support-card\">\r\n              <img src=\"assets/img/no-bootable-device.jpeg\" alt=\"Error no bootable device\">\r\n              <p>Referencia visual 1: mensaje clasico cuando el equipo no encuentra un medio valido de arranque.</p>\r\n            </div>\r\n            <div class=\"support-card\">\r\n              <img src=\"assets/img/sopa-letras.png\" alt=\"Sopa de letras\">\r\n              <p>Referencia visual 2: material de apoyo para la actividad de contextualizacion y vocabulario tecnico.</p>\r\n            </div>\r\n            <div class=\"notes-card\">\r\n              <h3>Sugerencias de uso</h3>\r\n              <ul class=\"note-list\">\r\n                <li>Usa la bitacora y el taller como base para estructurar tus entregas.</li>\r\n                <li>Consulta VirtualBox y Linux Boot Process antes de la practica de instalacion.</li>\r\n                <li>Apoya el informe final con los documentos de normas IEEE y ciberseguridad.</li>\r\n                <li>Guarda evidencias con nombres claros dentro de tu portafolio de aprendizaje.</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"modal-overlay\" id=\"guide5-export-modal\" onclick=\"if(event.target===this)closeGuide5ExportModal()\">\r\n  <div class=\"modal-box\">\r\n    <h3 id=\"guide5-export-title\">&#128196; Exportar actividad a Word</h3>\r\n    <p id=\"guide5-export-description\">Ingresa tu nombre completo para guardar el documento.</p>\r\n\r\n    <div class=\"modal-ficha-warn\" id=\"guide5-export-warn\" style=\"display:none\">\r\n      &#9888;&#65039; <strong>No has seleccionado tu ficha.</strong><br>\r\n      Regresa a <a href=\"index.html\">la p&aacute;gina de inicio</a> y elige tu instituci&oacute;n y grupo antes de exportar.\r\n    </div>\r\n\r\n    <div class=\"modal-ficha-ok\" id=\"guide5-export-ok\" style=\"display:none\">\r\n      <div class=\"mf-label\">&#128206; El archivo se guardar&aacute; como:</div>\r\n      <div class=\"mf-file\" id=\"guide5-export-filename\">Nombre_Ficha.doc</div>\r\n    </div>\r\n\r\n    <input\r\n      id=\"guide5-export-name\"\r\n      type=\"text\"\r\n      placeholder=\"Nombre y apellidos del aprendiz\"\r\n      maxlength=\"80\"\r\n      oninput=\"updateGuide5ExportFilenamePreview()\"\r\n      onkeydown=\"if(event.key==='Enter')doGuide5ExportWord()\"\r\n    >\r\n    <div class=\"modal-error-msg\" id=\"guide5-export-error\">Por favor ingresa tu nombre antes de continuar.</div>\r\n\r\n    <div class=\"modal-actions\">\r\n      <button class=\"modal-btn-cancel\" type=\"button\" onclick=\"closeGuide5ExportModal()\">Cancelar</button>\r\n      <button class=\"modal-btn-ok\" type=\"button\" id=\"guide5-export-ok-btn\" onclick=\"doGuide5ExportWord()\">&#11015; Descargar Word</button>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<div id=\"guia2-support-panel\" style=\"position:fixed;top:0;right:0;width:min(720px,100vw);height:100dvh;background:#f8fafc;box-shadow:-4px 0 32px rgba(0,0,0,.22);z-index:9999;transform:translateX(110%);transition:transform .35s cubic-bezier(.4,0,.2,1);display:flex;flex-direction:column;font-family:inherit\">\r\n  <div style=\"background:linear-gradient(135deg,#007934,#0a5c31);color:#fff;padding:16px 20px;display:flex;align-items:center;justify-content:space-between;flex-shrink:0\">\r\n    <div id=\"guia2-support-panel-title\" style=\"font-weight:700;font-size:1rem;line-height:1.3\"></div>\r\n    <button onclick=\"closeGuia2SupportPanel()\" style=\"background:rgba(255,255,255,.2);border:none;color:#fff;width:32px;height:32px;border-radius:50%;font-size:1.1rem;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-left:12px\">x</button>\r\n  </div>\r\n  <div id=\"guia2-support-panel-body\" style=\"flex:1;overflow-y:auto;padding:20px 18px\"></div>\r\n</div>\r\n<div id=\"guia2-support-backdrop\" onclick=\"closeGuia2SupportPanel()\" style=\"position:fixed;inset:0;background:rgba(0,0,0,.4);z-index:9998;opacity:0;pointer-events:none;transition:opacity .35s\"></div>\r\n\r\n<script>\r\nfunction buildGuideRouteHref(fileName) {\r\n  return \"guia.html?g=\" + encodeURIComponent(fileName);\r\n}\r\n\r\nfunction descargarMatrizWord() {\r\n  var a = document.createElement(\"a\");\r\n  a.href = \"assets/materiales/guia2/MatrizDiagnosticoDigital.docx\";\r\n  a.download = \"MatrizDiagnosticoDigital.docx\";\r\n  document.body.appendChild(a);\r\n  a.click();\r\n  document.body.removeChild(a);\r\n}\r\n\r\n(function () {\r\n  var grupo = String((document.body && document.body.dataset && document.body.dataset.defaultGrupo) || \"10A\").toUpperCase();\r\n  var config = {\r\n    \"10A\": {\r\n      currentFile: \"grupo-10a-guia-02-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 10A\",\r\n      previousFile: \"grupo-10a-guia-01-induccion.html\",\r\n      previousLabel: \"Induccion | 10A\",\r\n      campus: \"Jhon F. Kennedy | 10A\",\r\n      activity4Url: \"pages/auxiliares/grupo-10a-guia-02-actividad-4-formulario.html?v=20260409_6\",\r\n      fichaCasoUrl: \"pages/auxiliares/grupo-10a-guia-02-ficha-caso.html\",\r\n      matrizUrl: \"pages/auxiliares/grupo-10a-guia-02-actividad-322-matriz.html\"\r\n    },\r\n    \"10B\": {\r\n      currentFile: \"grupo-10b-guia-02-herramientas-informaticas-digitales.html\",\r\n      currentLabel: \"Operar herramientas informaticas y digitales | 10B\",\r\n      previousFile: \"grupo-10b-guia-01-induccion.html\",\r\n      previousLabel: \"Induccion | 10B\",\r\n      campus: \"Jhon F. Kennedy | 10B\",\r\n      activity4Url: \"pages/auxiliares/grupo-10b-guia-02-actividad-4-formulario.html?v=20260409_6\",\r\n      fichaCasoUrl: \"pages/auxiliares/grupo-10b-guia-02-ficha-caso.html\",\r\n      matrizUrl: \"pages/auxiliares/grupo-10b-guia-02-actividad-322-matriz.html\"\r\n    }\r\n  }[grupo] || null;\r\n\r\n  if (!config) {\r\n    return;\r\n  }\r\n\r\n  var currentGuideNavLink = document.getElementById(\"currentGuideNavLink\");\r\n  var currentGuideNavLabel = document.getElementById(\"currentGuideNavLabel\");\r\n  var previousGuideNavLink = document.getElementById(\"previousGuideNavLink\");\r\n  var previousGuideNavLabel = document.getElementById(\"previousGuideNavLabel\");\r\n  var topbarCampus = document.getElementById(\"topbarCampus\");\r\n  var activity4FormLink = document.getElementById(\"activity4FormLink\");\r\n  var fichaCasoLinks = document.querySelectorAll(\".fichaCasoLink, #fichaCasoLink\");\r\n  var matrizDiagnosticoLink = document.getElementById(\"matrizDiagnosticoLink\");\r\n\r\n  if (currentGuideNavLink) {\r\n    currentGuideNavLink.href = buildGuideRouteHref(config.currentFile);\r\n    currentGuideNavLink.dataset.currentFile = config.currentFile;\r\n  }\r\n  if (currentGuideNavLabel) {\r\n    currentGuideNavLabel.textContent = config.currentLabel;\r\n  }\r\n  if (previousGuideNavLink) {\r\n    previousGuideNavLink.href = buildGuideRouteHref(config.previousFile);\r\n    previousGuideNavLink.dataset.currentFile = config.previousFile;\r\n  }\r\n  if (previousGuideNavLabel) {\r\n    previousGuideNavLabel.textContent = config.previousLabel;\r\n  }\r\n  if (topbarCampus) {\r\n    topbarCampus.textContent = config.campus;\r\n  }\r\n  if (activity4FormLink) {\r\n    activity4FormLink.href = config.activity4Url;\r\n  }\r\n  if (fichaCasoLinks.length) {\r\n    fichaCasoLinks.forEach(function (link) {\r\n      link.href = config.fichaCasoUrl;\r\n    });\r\n  }\r\n  if (matrizDiagnosticoLink) {\r\n    matrizDiagnosticoLink.href = config.matrizUrl;\r\n  }\r\n})();\r\n</script>\r\n";
